class Solution {
    public boolean isFascinating(int n) {
        int twoN = 2 * n;
        int threeN = 3 * n;
        return (n % 1000 == 0 || n == twoN || n == threeN) && !(twoN.equals(n) || twoN.equals(threeN));
    }
}
